"use strict";(self.webpackChunk_N_E=self.webpackChunk_N_E||[]).push([[3669],{6050:e=>{e.exports=JSON.parse('{"lang.name":"한국어","nav.how":"작동 방식","nav.why":"마켓플레이스가 아닌 이유","nav.signin":"로그인","nav.request":"액세스 신청","hero.eyebrow":"비공개 탤런트 에이전시","hero.t1":"당신의 재능은 라이선스로.","hero.t2":"당신의 신원은 그대로 보호.","hero.sub":"SkillBridge는 검증된 클라이언트에게 당신의 기술을 라이선스합니다. 양측은 서로를 절대 볼 수 없습니다. 검색도, 입찰도, 바닥 치는 가격 경쟁도 없습니다. 평가\xb7매칭\xb7보호\xb7정산은 저희가 맡고, 크레딧\xb7로열티\xb7권리는 당신 몫입니다.","hero.ctaT":"라이선스할 재능이 있어요","hero.ctaC":"일을 맡기고 싶어요","how.eyebrow":"작동 방식","how.title":"두 세계. 하나의 벽. 그 벽이 바로 우리입니다.","how.talent":"탤런트","how.t1":"개인 IP 금고에 작업물을 업로드","how.t2":"서면 근거와 함께 공정 가치를 평가\xb7책정","how.t3":"익명화된 기회 수신: 범위\xb7예산\xb7기간","how.t4":"수락 후 플랫폼 통해 납품, 대금 + 크레딧 획득","how.core":"SkillBridge","how.s1":"모든 클라이언트 심사: 신원\xb7사용 목적\xb7윤리","how.s2":"알고리즘이 아닌 사람이 직접 매칭","how.s3":"양측의 익명 브리프 작성","how.s4":"에스크로 보관, 메시지 중계, 벽을 넘는 모든 접근 감사","how.client":"클라이언트","how.c1":"필요한 것을 알려주세요: 범위\xb7예산\xb7사용 목적","how.c2":"400개의 입찰이 아닌 엄선된 제안 하나","how.c3":"승인 후 에스크로 결제, 라이선스된 결과물 수령","how.c4":"누구인지는 끝까지 모른 채, 얼마나 뛰어난지만 확인 (등급 인증)","pr.eyebrow":"마켓플레이스가 아닙니다","pr.title":"탤런트 이코노미를 위한 길드","pr.1t":"검색 없음","pr.1b":"클라이언트는 탤런트끼리 비교하며 값을 깎을 수 없고, 탤런트도 좋은 클라이언트만 골라잡을 수 없습니다. 발견의 권한은 플랫폼에 있으며, 그것이 양방향 공정 가격을 지킵니다.","pr.2t":"입찰 없음","pr.2b":"작업의 가치는 경매가 아닌 평가로 정해집니다. 모든 가격에는 서면 근거가 있고, 라이선스 방식 덕분에 작업물이 계속 수익을 만듭니다 — 일회성이 아닌 로열티로.","pr.3t":"노출 없음","pr.3b":"라이선스가 체결되고 결제될 때까지 신원\xb7포트폴리오\xb7파일은 금고에 남습니다. 벽을 넘는 모든 직원 접근은 변경 불가한 감사 로그에 기록됩니다.","pr.trust":"신뢰를 구조로 증명합니다: 에스크로 결제 \xb7 첫 마이그레이션부터 적용된 행 수준 보안 \xb7 플랫폼 중계 메시지 \xb7 서명된 만료형 파일 접근 \xb7 벽을 넘는 모든 순간을 남기는 추가 전용 감사 로그.","wl.eyebrow":"얼리 액세스","wl.titleT":"창립 탤런트로 참여","wl.titleC":"창립 클라이언트로 참여","wl.tabT":"재능이 있어요","wl.tabC":"재능이 필요해요","wl.cta":"액세스 신청","wl.done":"명단에 등록되었습니다. 곧 연락드릴게요.","wl.dup":"이미 이 명단에 있는 이메일입니다.","wl.founding":"창립 코호트: 양측 각 선착순 100명은 평생 15%의 할인된 플랫폼 수수료와 우선 매칭을 확정합니다.","wl.spots":"석의 창립 멤버 자리가 이 편에 남았습니다","wl.blurbT":"작업물은 보호된 금고에 보관됩니다. 클라이언트는 당신이 누구인지 절대 알 수 없습니다 — 우리가 무엇을 전달할 수 있는지만 봅니다.","wl.blurbC":"필요한 것을 알려주세요. 등급 인증된 탤런트의 엄선된 제안 하나. 입찰 전쟁은 없습니다.","ft.tag":"마켓플레이스가 아닌, 당신을 위해 일하는 에이전시.","ft.rights":"모든 작업물 보호 \xb7 벽을 넘는 모든 접근 감사","auth.enter":"브리지 입장","auth.lede":"데모 모드 — 비밀번호 없음. 데모 페르소나로 세 세계를 둘러보거나 데모 계정 이메일을 사용하세요.","auth.orEmail":"또는 이메일로 계속","auth.signin":"로그인","auth.new":"처음이신가요?","auth.create":"계정 만들기","auth.side":"어느 쪽으로 참여하실지 선택하세요","auth.sideLede":"계정은 벽의 한쪽에만 속합니다. 탤런트는 작업을 라이선스하고, 클라이언트는 그것을 요청합니다. 상대편을 볼 수도, 보일 수도 없습니다.","auth.haveT":"재능이 있어요","auth.haveTsub":"내 기술과 작업물을 라이선스합니다","auth.needT":"재능이 필요해요","auth.needTsub":"필요한 일을 남기면 제안을 받습니다","auth.name":"이름","auth.email":"이메일","auth.already":"이미 가입하셨나요?","auth.vetNote":"클라이언트 계정은 거래 전 심사를 거칩니다 — 신원\xb7사용 목적\xb7윤리.","auth.talentNote":"신원 인증 시 매칭이 시작됩니다. 금고 업로드는 지금 바로 가능합니다.","pn.dash":"대시보드","pn.vault":"IP 금고","pn.opps":"기회","pn.credits":"크레딧","pn.msgs":"메시지","pn.needs":"내 니즈","pn.props":"제안","pn.lic":"라이선스","pn.signout":"로그아웃","hero.demo":"라이브 데모 둘러보기","hero.guarantee":"에스크로 보호 \xb7 직원 QA 검수 \xb7 모든 납품에 재매칭 또는 환불 보증","hero.chip1":"신원 심사를 거친 클라이언트","hero.chip2":"스킬 인증을 받은 탤런트","hero.chip3":"모든 납품 QA 검수","nav.wall":"벽의 작동 방식","wl.nextT":"다음 단계","wl.next1":"저희가 해당 측의 접수 기간을 검토한 뒤 온보딩 절차를 안내드립니다.","wl.next2":"탤런트: 금고 + 스킬 평가. 클라이언트: 신원 + 사용 목적 심사.","wl.next3":"첫 매칭은 저희 팀이 직접 만듭니다 — 피드가 아니라 저희에게서 먼저 소식이 갑니다.","wl.cohort":"모든 창립 멤버가 컨시어지급 케어를 받을 수 있도록 소규모 접수 기간 단위로 온보딩합니다.","cs.eyebrow":"예시 시나리오","cs.title":"브리지를 건너는 네 가지 방법","cs.note":"플랫폼의 작동 방식을 보여주는 가상의 시나리오입니다 — 다음 이야기의 주인공은 당신입니다.","cs.1n":"마야 \xb7 UX 디자이너","cs.1t":"금고에서 엑스퍼트 등급까지","cs.1b":"마야는 자신의 디자인 시스템을 금고에 업로드합니다. SkillBridge는 서면 근거와 함께 프리미엄 가치를 책정합니다. 며칠 뒤 익명화된 기회가 도착합니다 — 모바일 리디자인, $3,000–$5,000 구간, 3주. 그녀는 수락하고 플랫폼을 통해 납품하며, 80%에 더해 엑스퍼트 등급을 향한 크레딧을 얻습니다. 클라이언트는 그녀가 누구인지 끝내 알지 못합니다.","cs.2n":"제임스 \xb7 스타트업 창업자","cs.2t":"400개의 입찰이 아닌 제안 하나","cs.2b":"제임스는 Stripe 결제 API가 필요합니다. 그는 SkillBridge에 범위\xb7예산\xb7사용 목적을 알립니다. 48시간 안에 엄선된 제안 하나가 도착합니다: 마스터급 엔지니어, 결제 분야 인증 보유, $4,200, 3주, 에스크로 보호. 그는 승인합니다. 입찰과 포트폴리오의 바다를 헤맬 일은 없습니다.","cs.3n":"레나 \xb7 일러스트레이터","cs.3t":"일회성이 아닌 로열티","cs.3b":"레나는 에디토리얼 일러스트 평가를 통과합니다(91/100). 클라이언트는 그녀가 누구인지 보지 못한 채 이 배지만 봅니다. 라이선스된 시리즈는 매달 갱신됩니다. 새로운 에스크로 사이클, 명세서에 더해지는 또 한 번의 로열티, 다음 등급을 향해 쌓이는 크레딧. 신원은 봉인된 채, 수익만 꾸준히 들어오는 패시브 인컴입니다.","cs.4n":"Acme Corp \xb7 엔터프라이즈","cs.4t":"큰 작업을 위한 마일스톤","cs.4b":"Acme는 제품 사진 50장이 필요합니다. $8,500 규모의 계약은 마일스톤으로 나뉩니다 — 스튜디오 세트, 그다음 라이프스타일 세트 — 각각 별도로 입금되고, QA 검수를 거치고, 정산됩니다. 누구의 신원도 벽을 넘지 않으며, 모든 결과물에는 추적 가능한 라이선스 지문이 새겨집니다.","faq.eyebrow":"질문","faq.title":"당연한 질문, 솔직한 대답","faq.q1":"포트폴리오를 볼 수 없는데 클라이언트가 저를 어떻게 신뢰하죠?","faq.a1":"플랫폼이 보증하는 세 가지 신호가 당신 대신 벽을 넘습니다: 등급(쌓아 올린 평판), 인증(점수가 매겨진 플랫폼 공식 스킬 평가), 그리고 모든 납품에 붙는 SkillBridge의 QA 보증. 클라이언트는 플랫폼의 말을 신뢰합니다 — 그것이 바로 이 서비스입니다.","faq.q2":"대금은 언제, 어떻게 받나요?","faq.a2":"클라이언트는 작업 시작 전에 에스크로로 결제합니다. 납품물이 직원 QA를 통과하면 대금이 지급되며, 당신은 80%를 가져갑니다. 기간제 라이선스는 갱신될 때마다 반복 정산으로 이어지고, 모든 내역은 월간 로열티 명세서에 표시됩니다.","faq.q3":"제 작업물의 소유권은 누구에게 있나요?","faq.a3":"언제나 당신입니다. 작업물은 판매되는 것이 아니라 라이선스될 뿐입니다. 라이선스가 체결되고 결제될 때까지 파일은 암호화된 금고에 남고, 모든 결과물에는 라이선스별 비가시 지문이 새겨져 유출을 추적하고 대응할 수 있습니다.","faq.q4":"누가 만들었는지 볼 수 없는데 품질은 어떻게 판단하나요?","faq.a4":"품질을 예측하는 것들을 보게 됩니다: 검증된 등급, 인증 점수, 워터마크가 적용된 미리보기 발췌본, 납품 시 직원 QA 리포트 — 모두 재매칭 또는 환불 보증이 뒷받침합니다. 받지 않는 것은 단 하나, 판단을 흐릴 이름뿐입니다.","faq.q5":"납품물이 형편없으면 어떻게 되나요?","faq.a5":"SkillBridge 보증: 모든 납품물은 당신이 보기 전에 직원 QA 체크리스트를 통과합니다. 그래도 만족스럽지 않다면 분쟁 절차가 에스크로 자금을 동결하고, 사람이 직접 해결합니다 — 재매칭 또는 환불로.","faq.q6":"왜 탤런트를 직접 둘러볼 수 없나요?","faq.a6":"검색은 가격을 바닥으로 끌어내리고, 탤런트가 빼앗기고 베껴지고 소모되는 방식입니다. 큐레이션은 가장 목소리 큰 입찰자가 아니라 꼭 맞는 상대를 만나는 방식입니다. 벽은 양쪽 모두를 보호합니다 — 당신을 포함해서.","faq.q7":"비용은 얼마인가요?","faq.a7":"가입은 양쪽 모두 무료입니다. 클라이언트는 제안서에 적힌 금액만 지불합니다 — 숨은 수수료는 없습니다. 플랫폼은 거래마다 20%를 가져가며, 이는 심사\xb7가치 평가\xb7QA\xb7에스크로\xb7IP 보호에 쓰입니다.","faq.q8":"그냥 둘이서 직접 거래하면 안 되나요?","faq.a8":"약관상 금지되어 있습니다 — 하지만 더 현실적으로, 직거래는 에스크로, QA, 보증, 라이선스 집행, 그리고 다음 매칭을 모두 잃는다는 뜻입니다. 벽은 감옥이 아니라 서비스 그 자체입니다.","cmp.eyebrow":"솔직한 비교","cmp.title":"마켓플레이스도, 구식 에이전시도 아닙니다.","cmp.h2":"프리랜서 마켓플레이스","cmp.h3":"전통적 에이전시","cmp.r1":"큐레이션 매칭 — 검색도 입찰도 없음","cmp.r2":"모든 가격에 서면 가치 평가 근거","cmp.r3":"양측 모두 신원 보호","cmp.r4":"모든 납품에 에스크로 + QA 보증","cmp.r5":"탤런트를 위한 로열티와 크레딧 등급","cmp.legend":"✓ 기본 제공 \xb7 △ 경우에 따라 \xb7 ✗ 모델 자체가 다름","tier.eyebrow":"등급 사다리","tier.title":"크레딧이 쌓여 지위가 됩니다","tier.b1":"표준 요율, 첫날부터 완전한 보호","tier.b2":"더 높은 요율과 우선 매칭","tier.b3":"프리미엄 요율, 복지 기금 적립","tier.b4":"최상위 요율과 자문 참여","tier.b5":"최고 배정 우선권과 의사결정 테이블의 한 자리","td.welcome":"{name}님, 다시 오신 것을 환영합니다","td.sub":"재능은 곧 자산입니다. 저희가 그 자산을 지키고, 수익으로 이어지게 합니다.","td.earnings":"누적 수익","td.vault":"금고 보관 항목","td.opps":"열린 기회","td.newOpps":"SkillBridge가 보낸 새 기회","td.new":"신규","cd.hello":"안녕하세요, {name}님","cd.sub":"필요한 것을 알려주세요. 최고의 인재는 저희가 찾습니다 — 입찰의 바다를 헤맬 필요는 없습니다.","cd.vetT":"계정 심사 중입니다.","cd.vetB":"SkillBridge는 매칭 전에 모든 클라이언트를 심사합니다 — 신원과 사용 목적. 니즈 초안은 지금 작성할 수 있으며, 승인이 완료되면 매칭이 시작됩니다.","cd.needs":"열린 니즈","cd.props":"대기 중인 제안","cd.lic":"활성 라이선스","cd.newNeed":"+ 필요한 것을 알려주세요","cd.waiting":"결정을 기다리고 있어요","cd.proposal":"제안","op.title":"기회","op.sub":"담당 에이전트가 직접 매칭해 보냅니다. 전체 범위와 정산액은 볼 수 있지만, 클라이언트가 누구인지는 절대 보이지 않습니다. 수락하면 SkillBridge를 통해 납품할 것을 약속하게 됩니다.","op.empty":"아직 기회가 없습니다 — 저희가 찾는 중입니다. 승인된 금고 작업물이 먼저 매칭됩니다.","op.await":"답변 대기 중","op.client":"클라이언트","op.vetted":"(SkillBridge 심사 완료)","op.budget":"예산 구간","op.timeline":"일정","op.payout":"당신의 정산액","op.presented":"제시일","op.note":"SkillBridge에 보내는 메모 (질문, 조건 — 선택 사항)","op.accept":"기회 수락","op.decline":"거절","pp.title":"제안","pp.sub":"니즈당 엄선된 매칭 하나. 승인하면 에스크로에 입금되며, 탤런트는 납품이 검수를 통과한 후에만 대금을 받습니다.","pp.empty":"아직 제안이 없습니다 — 니즈를 매칭하는 중입니다.","pp.decision":"당신의 결정","pp.for":"해당 니즈","pp.talent":"탤런트","pp.tierVerified":"(SkillBridge 등급 인증)","pp.price":"가격 (총액)","pp.timeline":"일정","pp.received":"수신일","pp.milestones":"마일스톤 결제 — 한 번에 하나씩 입금","pp.guarantee":"SkillBridge 보증 적용: 직원 QA 검수를 거친 납품, 에스크로 자금 보관, 불만족 시 재매칭 또는 환불.","pp.feedback":"피드백 (대안 요청 시 필수)","pp.approve":"승인 — 에스크로 {amount} 입금","pp.alt":"대안 요청","pp.decline":"거절","pp.escrowed":"✓ 에스크로 입금 완료. 작업이 진행 중이며, 준비되는 대로 납품물이 여기에 도착합니다.","vp.title":"IP 금고","vp.add":"+ 작업물 추가","vp.sub":"이곳의 모든 것은 저장 시 암호화되며 클라이언트에게는 보이지 않습니다. 승인된 작업물은 매칭 대상이 되고, 라이선스된 작업물은 정산과 크레딧을 만들어 줍니다.","vp.empty":"금고가 비어 있습니다 — 첫 작업물을 업로드해 크레딧을 쌓기 시작하세요.","vp.review":"심사 중","vp.matchable":"금고 보관 중 \xb7 매칭 가능","vp.licensed":"라이선스됨","vp.valuation":"플랫폼 가치 평가:","vp.note":"심사 메모:","vp.ask":"희망가 {amount}","lp.title":"라이선스","lp.sub":"모든 납품물은 당신에게 도착하기 전에 직원 QA를 통과하고, 추적 가능한 라이선스 지문이 새겨지며, SkillBridge 보증의 보호를 받습니다: 불만족 시 재매칭 또는 환불.","lp.empty":"아직 라이선스가 없습니다 — 제안을 승인하면 생성됩니다.","lp.active":"활성","lp.revoked":"해지됨","lp.type":"유형","lp.use":"라이선스된 용도","lp.terms":"조건","lp.price":"가격","lp.escrow":"에스크로","lp.started":"시작일","lp.expires":"만료일","lp.perpetual":"영구 (조건에 따름)","lp.fp":"지문","lp.fpTitle":"납품물에 삽입되어 있어 유출 시 어느 사본에서 새어 나갔는지 추적할 수 있습니다","lp.qa":"QA 리포트 — {date} 통과","lp.download":"⬇ 납품물 다운로드","lp.pendingQa":"(QA 대기 중)","lp.dispute":"납품에 문제가 있나요? 분쟁 제기","lp.disputeLabel":"무엇이 잘못되었나요? (영업일 기준 1일 이내에 사람이 직접 검토합니다)","lp.disputeSubmit":"분쟁 제출 — 자금 동결","lp.renewT":"갱신 제안","lp.renewB":"{amount}로 이 라이선스를 30일 연장하세요 — 동일 조건, 에스크로 보호.","lp.renew":"갱신 — 에스크로 {amount} 입금","lp.expire":"만료되도록 두기","lp.milestones":"마일스톤","lp.fundNext":"다음 마일스톤 입금 — {amount}","vu.t_design":"디자인","vu.t_code":"코드","vu.t_image":"이미지","vu.t_document":"문서","vu.t_audio":"오디오","vu.t_video":"비디오","bq.l_title":"구체적인 제목 (12자 이상)","bq.h_title":"결과물을 콕 집어 주세요. \\"도움 필요\\"가 아니라 \\"Stripe 연동 결제 API\\"처럼.","bq.l_description":"상세 설명 (80자 이상)","bq.h_description":"작업 범위, 제약 조건, 그리고 \\"완료\\"의 기준이 무엇인지 적어 주세요.","bq.l_budget":"현실적인 예산 범위","bq.h_budget":"범위를 알려주시면 딱 맞는 등급의 탤런트를 매칭해 드립니다.","bq.l_timeline":"기간 명시","bq.h_timeline":"\\"4주\\"도 \\"유연하게\\"도 좋습니다. 아무 말이 없는 것만 곤란합니다.","bq.l_use":"명확한 사용 목적 (20자 이상)","bq.h_use":"라이선스 조건이 여기서 만들어집니다. 구체적일수록 윤리 검토가 빨라집니다.","hw.h1a":"사람은 들여다볼 수 없습니다.","hw.h1b":"그러니 구조를 들여다보세요.","hw.sub":"마켓플레이스는 낯선 이의 프로필을 믿으라고 합니다. 저희는 한 단계씩 직접 읽어 볼 수 있는 절차를 믿으시라고 합니다. 모든 거래가 예외 없이 같은 다섯 관문을 거칩니다.","hw.g1t":"1 \xb7 심사","hw.g1b":"클라이언트는 거래에 앞서 신원을 증명하고 사용 목적을 밝힙니다. 탤런트는 근거와 함께 스킬을 등록하고 플랫폼 공식 평가에 응시합니다. 심사를 통과하지 않고는 아무도 문턱을 넘지 못합니다.","hw.g2t":"2 \xb7 매칭","hw.g2b":"사람 매처가 투명한 스코어링 모델의 도움을 받아 니즈와 알맞은 금고 작업물을 짝지어 줍니다. 모델이 사람을 대신하는 일은 없습니다. 양측 브리프는 플랫폼의 어조로 다시 쓰이고, 문체 분석 코파일럿이 신원을 드러낼 만한 표현을 잡아냅니다.","hw.g3t":"3 \xb7 에스크로","hw.g3b":"클라이언트는 작업 시작 전에 마일스톤 대금을 예치합니다. 자금은 플랫폼이 보관합니다. 탤런트는 대금이 실재함을, 클라이언트는 언제든 회수할 수 있음을 압니다.","hw.g4t":"4 \xb7 QA","hw.g4b":"모든 결과물은 클라이언트에게 닿기 전에 직원 체크리스트를 통과합니다. 요구 범위 충족, 신원 노출 제로, 문서 포함 여부까지. QA 리포트는 납품물과 함께 전달됩니다.","hw.g5t":"5 \xb7 보증","hw.g5b":"납품이 기준에 못 미치면 재매칭 또는 환불. 분쟁이 제기되면 사람이 해결할 때까지 자금이 동결됩니다. 모든 납품물에는 라이선스별 비가시 지문이 새겨져, 유출을 추적하고 대응할 수 있습니다.","hw.intEyebrow":"설계로 지키는 무결성","hw.intTitle":"벽은 정책이 아니라 아키텍처입니다.","hw.i1t":"행 수준 보안","hw.i1b":"첫 데이터베이스 마이그레이션부터 양측의 데이터는 서로 읽을 수 없습니다. 애플리케이션의 배려가 아니라 데이터베이스 그 자체가 강제하는 규칙입니다.","hw.i2t":"열 수준 권한","hw.i2b":"라이선스처럼 양측이 공유하는 레코드에서도 상대의 이름이 담긴 열은 읽을 수 없습니다. 벽은 하나의 행 안에도 존재합니다.","hw.i3t":"감사되는 교차","hw.i3b":"플랫폼 직원은 양측을 볼 수 있지만, 그런 접근은 하나도 빠짐없이 추가 전용 감사 로그에 기록됩니다. 벽에는 블랙박스가 달려 있습니다.","hw.i4t":"하나의 목소리","hw.i4b":"모든 메시지는 플랫폼을 거쳐 중계됩니다. 신원 스크러버가 이메일\xb7전화번호\xb7계정을 걸러낸 뒤에야 사람 모더레이터가 한마디를 전합니다.","hw.verify":"납품물을 가진 누구나 {link}에서 라이선스를 확인할 수 있습니다. 계정도 필요 없습니다.","vf.title":"라이선스 조회","vf.sub":"모든 SkillBridge 납품물에는 라이선스 번호와 삽입된 지문이 담겨 있습니다. SB로 시작하는 번호를 여기서 확인해 보세요. (데모 레지스트리)","vf.check":"조회","vf.valid":"✓ 유효하며 효력 있음","vf.expired":"⏱ 만료됨","vf.revoked":"✗ 해지됨","vf.notfound":"✗ 해당 번호의 라이선스가 없습니다. 이 문서는 라이선스가 없는 것으로 간주하세요.","vf.license":"라이선스","vf.issued":"발급일","vf.note":"라이선시와 창작자의 신원은 어떤 경우에도 공개되지 않습니다. 오용이 의심되시나요? 라이선스 번호와 함께 SkillBridge로 문의해 주세요.","ob.title":"매칭 준비 — {done}/{total}","ob.profile":"프로필 완성 (소개)","ob.skill":"스킬 등록 (+25 크레딧)","ob.vault":"금고에 작업물 업로드 (+50 크레딧)","ob.cert":"평가 응시 (합격 시 +100 크레딧)","tr.toNext":"{tier}까지 {n} 크레딧","tr.top":"사다리의 정점 — 자문 좌석이 열렸습니다","sk.title":"스킬","sk.sub":"등록한 스킬이 어떤 기회가 당신에게 닿을지를 결정합니다 (스킬당 +25 크레딧). 저희 팀이 근거를 검증하며, 검증된 스킬은 매칭에서 더 높은 순위에 놓입니다.","sk.skill":"스킬","sk.skillPh":"예: 결제 인프라","sk.cat":"카테고리","sk.years":"경력 연수","sk.evidence":"근거 링크 (포트폴리오, 리포지토리 — 오직 SkillBridge 직원만 열람)","sk.add":"스킬 등록 (+25 크레딧)","sk.empty":"아직 등록된 스킬이 없습니다.","sk.verified":"✓ 검증됨","sk.pending":"검증 대기 중","ct.title":"인증","ct.sub":"클라이언트는 당신의 포트폴리오를 볼 수 없습니다. 그게 핵심입니다. 그럼에도 당신의 탁월함을 알아보게 하는 것이 바로 인증입니다. 플랫폼이 채점하고, 신원은 드러나지 않으며, 당신에 관한 모든 제안서에 함께 실립니다.","ct.earned":"취득함","ct.awaiting":"채점 대기 중","ct.available":"응시 가능한 평가","ct.none":"카테고리에 남은 평가가 없습니다. 새 평가는 수시로 추가됩니다.","ct.pass":"{score}/100 이상 합격 \xb7 SkillBridge 직원 채점 \xb7 +100 크레딧","ct.take":"평가 응시","ct.close":"닫기","ct.ph":"답안을 입력하세요…","ct.submit":"채점 제출","ct.grading":"채점 중","ct.certified":"인증 취득: {title}","st.title":"로열티 명세서","st.sub":"모든 정산을 월별로 정리했습니다. 최초 라이선스든 갱신이든 빠짐없이 담깁니다. PDF와 세무 요약은 정식 결제 시스템과 함께 제공됩니다.","st.empty":"아직 지급된 로열티가 없습니다. 라이선스에서 정산이 발생하면 여기에 표시됩니다.","st.gross":"라이선스 총액","st.fee":"플랫폼 수수료","st.net":"실수령액","st.netShort":"실수령 {amount}","st.paid":"{date} 지급","vu.title":"금고에 작업물 추가","vu.sub":"업로드하면 50 크레딧이 적립됩니다. 저희 팀이 모든 작품을 검토하고 가치를 책정하며, 그 평가와 근거는 금고에서 확인하실 수 있습니다.","vu.desc":"설명 — 어떤 작업물이며, 무엇이 이 작업물을 가치 있게 만드나요?","vu.type":"작업물 유형","vu.price":"희망가 (USD, 선택 사항 — 가치는 저희가 독립적으로 책정합니다)","vu.license":"선호하는 라이선스 유형","vu.lic_peruse":"사용당 (사용할 때마다 로열티)","vu.lic_time":"기간제 (반복 정산)","vu.lic_perp":"영구 라이선스(1회 결제, 무기한 사용)","vu.lic_excl":"독점 (프리미엄)","vu.files":"파일 — 사진, 비디오, 오디오, 문서","vu.filesNote":"데모 모드에서는 이미지 미리보기가 기기에만 저장됩니다. 실제 서비스에서는 원본이 비공개 금고 버킷으로 들어가며 외부에서는 결코 접근할 수 없습니다.","vu.submit":"금고에 제출 (+50 크레딧)","sp.profile":"프로필 (비공개 — 상대편에게는 절대 보이지 않습니다)","sp.name":"이름","sp.bio":"소개 (내부용 — 매칭 팀에 도움이 됩니다)","sp.avail":"작업 가능 여부","sp.avail_available":"가능 — 매칭해 주세요","sp.avail_busy":"바쁨 — 여력이 제한적입니다","sp.avail_away":"부재 — 매칭을 잠시 멈춥니다","sp.capacity":"가용 시간 (주당 시간)","sp.save":"프로필 저장","sp.saved":"✓ 저장됨","sp.prefs":"환경설정","sp.lang":"언어","sp.currency":"함께 표시할 통화","sp.currencyNote":"정산은 USD로 이루어지며, 다른 통화는 참고용 근사치로 표시됩니다.","sp.refer":"탤런트를 추천하고 크레딧을 받으세요","sp.referNote":"코드를 공유하세요 — 가입 시 +100 크레딧. 코드에는 어떤 신원 정보도 담기지 않습니다.","sp.tier":"계정 등급","sp.tierEnt":"\uD83C\uDFE2 엔터프라이즈 — 마스터/에메리투스 접근","sp.tierStd":"스탠다드","sp.tierNote":"엔터프라이즈 등급(더 깊은 심사, 최상위 탤런트 접근)은 저희 팀이 부여합니다.","sp.data":"내 데이터","sp.export":"⬇ 내 데이터 다운로드 (JSON)","sp.exportNote":"오직 당신 자신의 기록만 담깁니다. 이 내보내기 역시 다른 모든 것과 마찬가지로 벽을 지킵니다.","sp.demo":"데모","sp.reset":"데모 환경을 초기 상태로 되돌리기","sp.subT":"작업 가능 여부가 매칭 우선순위를 좌우합니다. 이곳의 모든 정보는 벽의 당신 쪽에 머뭅니다.","sp.subC":"당신의 정보는 당신과 SkillBridge 직원에게만 보입니다. 탤런트에게는 결코 보이지 않습니다.","sp.title":"설정","nb.title":"알림","nb.empty":"아직 아무 알림도 없습니다.","nb.markRead":"모두 읽음 처리","pm.title":"메시지","pm.subT":"하나의 대화창: 당신과 SkillBridge. 중요한 이야기는 양방향으로 저희가 전해 드립니다.","pm.subC":"하나의 대화창: 당신과 SkillBridge. 니즈\xb7제안\xb7라이선스에 관한 질문은 여기로 오세요.","pm.empty":"아직 메시지가 없습니다. 담당 에이전트에게 한마디만 남겨 보세요.","pm.you":"나","pm.ph":"SkillBridge에 메시지…","pm.note":"모든 소통은 SkillBridge 직원이 중계합니다. 신원을 드러내는 정보(이메일\xb7전화번호\xb7링크)는 벽을 넘기 전에 제거됩니다.","w.title":"필요한 것을 알려주세요","w.s1":"카테고리","w.s2":"설명","w.s3":"예산과 일정","w.s4":"사용 목적","w.s5":"검토","w.kind":"어떤 종류의 작업인가요?","w.titleQ":"짧은 제목을 붙여 주세요","w.titlePh":"예: Stripe 연동 결제 처리 API","w.desc":"원하는 결과물을 설명해 주세요 (누가 만들지가 아니라)","w.budgetFrom":"예산 최소 (USD)","w.budgetTo":"최대 (USD)","w.timeline":"일정","w.timelinePh":"예: 4주 / 유연하게","w.use":"이 작업물을 어떻게 사용하실 건가요? (필수 — 윤리 팀이 검토합니다)","w.usePh":"예: 자사 SaaS 제품의 핵심 결제, 내부 사용 전용","w.useNote":"라이선스 조건은 이 선언을 바탕으로 만들어집니다. 선언한 목적을 벗어난 사용은 라이선스를 무효화할 수 있습니다.","w.quality":"브리프 품질: {score}/100 ({grade})","w.qualityNote":"탄탄한 브리프일수록 매칭이 빨라집니다. 이 점수가 제출을 막는 일은 없습니다.","w.category":"카테고리","w.budget":"예산","w.flexible":"유연하게","w.submit":"SkillBridge에 제출","nl.title":"내 니즈","nl.new":"+ 새 니즈","nl.sub":"모든 니즈는 사람이 직접 매칭합니다. 입찰의 홍수가 아니라 엄선된 제안 하나를 받으시게 됩니다.","nl.empty":"아직 아무것도 없습니다. 필요한 것을 알려주시면 꼭 맞는 탤런트를 찾아 드립니다.","nl.h_submitted":"접수됨 — 저희 팀이 브리프를 검토하고 있습니다.","nl.h_reviewing":"꼭 맞는 탤런트를 찾고 있습니다.","nl.h_proposals_sent":"제안이 도착해 기다리고 있습니다.","nl.h_in_progress":"작업 진행 중 — 자금은 에스크로에 안전하게 보관 중입니다.","nl.h_completed":"납품 및 라이선스 완료. 감사합니다!","nl.h_cancelled":"취소됨.","nl.submitted":"{ago} 제출","cr.title":"크레딧과 등급","cr.sub":"크레딧은 업로드\xb7라이선스\xb7품질에서 쌓입니다. 크레딧이 오르면 요율도, 매칭 우선순위도, 길드에서의 지위도 함께 올라갑니다.","cr.ladder":"등급 사다리","cr.here":"현재 위치","cr.min":"{n} 크레딧 이상","cr.ledger":"적립 내역","cr.r_skill_registration":"스킬 등록","cr.r_work_upload":"작업물 업로드","cr.r_license_revenue":"라이선스 수익","cr.r_quality_bonus":"품질 보너스","cr.r_tenure":"활동 기간","cr.r_peer_review":"동료 평가","cr.r_certification":"인증","cr.r_referral":"추천","cr.r_adjustment":"조정","tour.skip":"투어 건너뛰기","tour.next":"다음","tour.done":"시작하기","tourT.1t":"금고는 당신의 자산입니다","tourT.1b":"작업물을 여기에 업로드하세요. 저희 팀이 모든 작품의 가치를 서면 근거와 함께 책정합니다 — 클라이언트는 원본 파일을 절대 보지 못합니다.","tourT.2t":"노출 없이 실력을 증명","tourT.2b":"인증 평가에 응시하세요. 클라이언트가 보는 것은 배지(타이틀 + 점수)뿐 — 당신의 이름이나 포트폴리오는 결코 보이지 않습니다.","tourT.3t":"기회가 당신을 찾아옵니다","tourT.3b":"저희가 직접 매칭해 익명 브리프를 보냅니다: 범위, 예산 구간, 당신의 정산액. 수락 또는 거절만 하면 됩니다 — 입찰은 없습니다.","tourT.4t":"크레딧이 쌓여 지위가 됩니다","tourT.4b":"업로드, 인증, 라이선스된 작업이 크레딧을 만듭니다. 등급이 오르면 요율과 매칭 우선순위가 높아지고, 로열티는 명세서에 표시됩니다.","tourC.1t":"필요한 것을 알려주세요","tourC.1b":"위저드가 범위, 예산, 사용 목적을 수집합니다 — 라이선스의 토대가 되는 윤리 선언입니다.","tourC.2t":"400개의 입찰이 아닌 제안 하나","tourC.2b":"엄선된 제안 하나를 보내드립니다: 등급, 인증, 워터마크 미리보기, 가격, 일정.","tourC.3t":"처음부터 끝까지 보호","tourC.3b":"승인하면 에스크로에 입금됩니다. 모든 납품은 직원 QA를 거치며 재매칭 또는 환불 보증이 적용됩니다.","tourC.4t":"라이선스는 여기에 모입니다","tourC.4b":"납품물, QA 리포트, 지문, 갱신, 분쟁 — 모두 「라이선스」 메뉴에 모여 있습니다.","c.send":"보내기","c.back":"뒤로","c.next":"계속","c.submit":"제출","vu.exp":"공개 수준","vu.exp_concierge":"컨시어지 전용 — 팀이 대신 제안하며 작품 자체는 절대 노출되지 않습니다","vu.exp_card":"메타데이터 카드 — 클라이언트는 사양만 볼 수 있고 작품은 볼 수 없습니다","vu.exp_preview":"프리뷰 허용 — 워터마크와 추적 코드가 들어간 발췌본만 표시됩니다","vu.expNote":"작품별 공개 범위는 직접 관리하실 수 있습니다. 기본값은 컨시어지 전용이며, 모든 프리뷰에는 워터마크와 열람자별 고유 코드가 들어가고 공개 이력 대조를 먼저 거칩니다.","pp.trace":"이 프리뷰에는 회원님 계정 고유 코드가 들어 있어 유출 시 추적할 수 있습니다.","pp.previewAlt":"워터마크가 적용된 작품 프리뷰(발췌)","vp.added":"{ago} 추가됨","vp.licensedX":"라이선스 \xd7{n}","pm.ack":"접수되었습니다 — 컨시어지가 영업일 기준 1일 이내에 답변드립니다.","lp.disputeEvidence":"증빙 자료(스크린샷, 파일)","lp.disputeEvidenceNote":"첨부 파일은 사람 심사자에게만 전달되며 상대방에게는 절대 공개되지 않습니다.","sp.delTitle":"계정 삭제","sp.delNote":"삭제는 담당자가 30일 이내에 처리합니다. 라이선스나 결제와 연결된 기록은 법률에 따라 삭제 대신 익명화하여 보관합니다.","sp.delBtn":"삭제 요청","sp.delDone":"요청이 접수되었습니다. 메시지로 확인해 드리겠습니다.","sp.privacyLink":"개인정보 처리방침","sp.termsLink":"이용약관","c.offline":"오프라인 상태입니다 — 열람은 가능하며, 변경에는 연결이 필요합니다.","vu.buy":"바이아웃 제안 허용","vu.buyNote":"기본값은 꺼짐입니다. 바이아웃은 이 작품을 완전히 파는 것을 뜻합니다. 클라이언트가 먼저 요청할 때만 견적을 내며, 라이선스 가격의 4배 아래로는 절대 내려가지 않고, 서명 전에 그것이 몇 년치 라이선스 수입에 해당하는지 반드시 보여 드립니다.","pp.buyoutTitle":"바이아웃 옵션(완전한 소유를 문의하셨습니다)","pp.buyoutNote":"{amount}에 전체 양도 — 최종 결제와 함께 지식재산권이 이전되며 갱신은 없습니다. 라이선스 약 {n}년치에 해당합니다.","pp.buyoutAccept":"완전히 소유하기 — {amount} 에스크로 예치","op.buyout":"바이아웃 제안이 논의 중입니다: 수령액은 {amount}(라이선스 수입 약 {n}년치)입니다. 결정 전에 컨시어지가 내용을 함께 검토해 드립니다.","sp.memTitle":"컨시어지 멤버십","sp.memPitch":"연회비 {amount} 하나로 엄선된 매칭 {n}회, 전담 컨시어지, 우선 응대, 고정 요금이 모두 포함됩니다. 건별로 결제할 필요가 없습니다.","sp.memBtn":"멤버 가입 — 연 {amount}","sp.memActive":"멤버 — 선불 매칭 {n}회 남음","sp.memPerks":"우선 응대 \xb7 전담 컨시어지 \xb7 고정 요금. 프로젝트별 에스크로는 기존 그대로입니다.","sc.title":"선반에 준비되어 있습니다","sc.sub":"이 카테고리에는 이미 검증과 품질 확인을 거친 작품이 있어 신규 의뢰보다 빠르게 라이선스할 수 있습니다. 자세한 내용은 컨시어지가 안내합니다.","sc.qa":"품질 검수 통과","sc.ask":"컨시어지에게 문의","sc.asked":"컨시어지에게 전달됨","vf.pv_title":"출처 증명서","vf.pv_human":"사람이 만든 작품 — 생성물이 아닙니다","vf.pv_id":"제작자 신원은 SkillBridge가 확인했습니다","vf.pv_created":"라이선스 발급","vf.pv_qa":"사람 검수자가 품질 확인","vf.pv_delivered":"핑거프린트를 심어 전달","vf.pv_note":"위의 모든 단계는 수정 불가능한 감사 로그에 기록됩니다. 제작자는 익명으로 남지만, 저작 증명은 남습니다.","hero.prov":"사람이 만든 작품 인증","vq.score":"등록 완성도: {score}%","vq.gate":"심사 제출에는 60%가 필요합니다. 위 체크리스트가 부족한 부분을 알려 줍니다.","vq.l_title":"명확한 제목(12자 이상)","vq.h_title":"얼마나 좋은지가 아니라 무엇인지를 쓰세요.","vq.l_desc":"설명에 충분한 사실이 담김","vq.h_desc":"80자 이상, 수량\xb7형식\xb7포함 내용 같은 구체 정보 포함.","vq.l_evidence":"증빙 첨부됨","vq.h_evidence":"작품의 실재를 보여 주는 파일, 스크린샷, 링크를 추가하세요.","vq.l_price":"희망 가격 설정됨","vq.h_price":"제시 가격이 저희 평가의 기준점이 됩니다. 나중에 조정 가능합니다.","vq.c_software":"코드: 언어, 테스트 커버리지, 문서 상태, 실행에 필요한 것.","vq.c_design":"디자인: 화면/컴포넌트 수, 사용 도구(Figma?), 다크 모드, 접근성 수준.","vq.c_illustration":"일러스트: 점수(개수), 스타일, 원본 파일 형식, 허용 용도.","vq.c_writing":"글쓰기: 단어 수, 주제 분야, 리서치 깊이, 퇴고 상태.","vq.c_media":"사진/영상: 컷 수, 해상도, 편집 상태, 인물 등장 시 초상권 동의서.","vq.c_data":"데이터: 파이프라인 단계, 도구 구성, 테스트 커버리지, 샘플 출력.","vq.exTitle":"모범 예시 보기","vq.example":"디자인 시스템 — 컴포넌트 120개, Figma\\n\xb7 14개 카테고리 120개 컴포넌트, 라이트+다크\\n\xb7 WCAG AA 대비 확인; 토큰 문서화\\n\xb7 포함: Figma 파일, 토큰 JSON, 사용 가이드\\n\xb7 8개월간 단독 제작; 출시 제품 2곳에서 사용","vq.coach":"AI 코치에게 부족한 점 물어보기","vp.changes":"수정 필요","vp.fix":"심사 라운드 {n} — 아래를 고쳐 다시 제출하세요","vp.resubmit":"다시 제출","vp.askChat":"컨시어지에게 문의","rc.evidence":"작품 실재의 증빙을 추가하세요(파일, 스크린샷, 링크)","rc.scope":"범위를 구체화하세요: 정확히 무엇이, 어떤 형식으로 포함되는지","rc.rights":"권리를 명확히: 구매자가 무엇을 할 수 있고 무엇이 내 것으로 남는지","rc.price":"가격을 범위에 맞추세요(또는 그 가격의 근거를 밝히세요)","tb.title":"매칭 자격까지의 여정","tb.s_unverified":"선발제 입장입니다 — 역량 평가 1회 통과로 자격을 얻습니다.","tb.s_assessed":"평가 통과 — 클라이언트 매칭까지 두 단계 남았습니다.","tb.m_assessment":"역량 평가 통과(무료, 사람이 채점)","tb.m_identity":"신원 인증","tb.m_vault":"금고 작품 1건 승인받기","ct.cooldown":"첫 불합격 후 14일이 지나면 재응시할 수 있습니다(이후 불합격은 30일). 채점 기준을 보며 답이 아닌 실력을 다듬으세요.","ct.rubric":"채점 기준: 합격 답안이 보여야 하는 것","auth.selective":"선발제 입장: 매칭 전에 평가 1회 통과가 필요합니다.","vq.l_auth":"저작자 확인 가능","vq.h_auth":"당신의 작품임을 어떻게 확인할 수 있는지 적어 주세요: 저장소 히스토리, 레이어가 있는 원본 파일, 작업 과정 캡처, 라이브 시연.","vu.auth":"이 작품이 본인 것임을 어떻게 확인할 수 있나요?","vu.authPh":"예: 2년치 커밋이 있는 비공개 저장소; 레이어 있는 Figma 파일; 작업 과정 녹화","ct.aiDecl":"이것은 저의 작품입니다. AI 도움이 있었다면 위에 신고했습니다. 인증이 인간 저작을 보증함을 이해합니다.","bq.l_realism":"예산이 범위에 부합","bq.h_realism":"이 카테고리치고 예산이 유난히 낮습니다. 매칭 전에 컨시어지가 범위 조율을 위해 연락드립니다.","lp.guarSusp":"반복적으로 기각된 분쟁으로 이 계정의 보증이 일시 중지되었습니다. 컨시어지에게 문의하세요.","tb.eta":"대부분 약 7일이면 모든 단계를 마칩니다.","dd.title":"수요가 있는 곳(최근 30일)","dd.none":"지금은 열린 요청이 없습니다. 새 요청이 여기 표시됩니다.","pp.why":"이 매칭의 이유","db.prompt":"전달은 어떠셨나요? 두 가지 질문 — 내부용이며 절대 공개되지 않습니다.","db.q1":"전달된 작업의 품질(1–5)","db.q2":"이 상대와 다시 일하시겠습니까?(1–5)","db.send":"디브리핑 보내기","db.thanks":"감사합니다 — 향후 매칭 조정에 쓰이며 누구에게도 공개되지 않습니다.","fl.title":"SkillBridge의 제안","fl.buyer":"구매자는 SkillBridge 자신입니다 — 공개적으로 알립니다. 거절해도 매칭에는 아무 영향이 없습니다.","fl.advTerms":"카탈로그 선지급: 지금 {amount}를 받고 {months}개월 독점 재라이선스를 부여합니다. 로열티에서 회수하며, 판매하지 못하면 권리는 반환됩니다.","fl.tail":"향후 어떤 재판매에도 로열티 테일이 계속 지급됩니다.","fl.accept":"제안 수락","fl.decline":"거절","fl.declineNote":"거절함 — 매칭에는 영원히 아무 영향이 없습니다.","fl.accepted":"수락됨 — 결제가 진행 중입니다. 작품 소유권은 그대로 당신 것입니다.","sp.portfolio":"공개 포트폴리오(한 줄에 링크 하나)","sp.portfolioNote":"본인의 갤러리와 저장소를 등록하세요. 도용 검사에서 그곳의 작품이 발견되면 그것이 바로 당신 작품이라는 증거가 됩니다. 등록된 링크는 당신을 보호할 뿐, 절대 불리하게 작용하지 않습니다.","ai.title":"무엇이 \\"사람이 만든 작품\\"인가요? AI 규칙을 쉬운 말로","ai.ok":"한 줄 신고와 함께라면 괜찮습니다: 아이디어, 초안, 섬네일, 밑그림, 코드 자동완성, 문법 교정에 AI 사용 — 최종 작품을 본인이 직접 만들고 마무리하는 한.","ai.no":"사람이 만든 작품이 아닌 것: 최종 결과물 대부분이 기계 생성이고 가벼운 수정만 거친 경우. 인증할 수 없으며, 서명하는 신고서는 법적 약속입니다.","ai.how":"자신의 경우가 어디에 속하는지 모르겠다면 제출 전에 컨시어지에게 물어보세요. 질문은 절대 불이익이 되지 않습니다.","faq.q9":"20% 수수료는 실제로 어디로 가나요? 위에 얹히나요?","faq.a9":"위에 얹히는 것은 없습니다. 승인하는 가격이 전부입니다. 예: 제안서에 $5,000 — 정확히 $5,000를 지불하고, 인재가 $4,000(80%)를 받으며 SkillBridge가 $1,000(20%)를 남겨 심사\xb7에스크로\xb7사람의 품질 검수\xb7재매칭 또는 환불 보증에 씁니다.","tb.cap":"현재 건당 한도: {amount}.","tb.capNext":"다음 단계: 깨끗한 납품 {n}회 후 {amount}.","tb.uncapped":"한도 없음 — 신뢰 사다리 최상단입니다.","lp.again":"이 인재와 다시 일하기","lp.againDone":"접수했습니다. 다음 의뢰 때 조건이 맞으면 이 탤런트를 우선 배정하겠습니다.","lp.comp":"컴플라이언스 공개 요청(NDA 하에 작업자 실명 공개)","lp.compNote":"엔터프라이즈 전용. 탤런트의 서면 동의와 NDA 체결 후, 컴플라이언스 검토(벤더 감사, BAA)를 위해 작업자 이름을 공유합니다. 모든 공개는 기록됩니다.","lp.compPending":"공개 요청이 접수되었습니다. 탤런트 동의와 NDA를 조율하고 있습니다.","lp.compOk":"NDA 하에 공개가 완료되었습니다.","lp.mask":"마스킹 작업 세션 요청(현재 마일스톤)","lp.maskNote":"크리에이티브 작업 전용: 마일스톤당 1회, 방향을 확인하는 라이브 세션입니다. 플랫폼이 주최하고 음성이 변조되며 탤런트는 익명을 유지합니다.","lp.maskDone":"세션을 요청했습니다. 컨시어지가 일정을 잡고 있습니다.","lp.maskOk":"세션이 예약되었습니다. 컨시어지가 보내는 링크를 확인하세요.","tc.title":"귀하의 동의가 필요합니다","tc.sessB":"클라이언트가 현재 마일스톤에 대한 라이브 작업 세션을 요청했습니다. 플랫폼이 주최하고 음성이 변조되며 익명이 유지됩니다. 거절해도 불이익이 없습니다.","tc.discB":"엔터프라이즈 클라이언트가 컴플라이언스 검토(예: 벤더 감사)를 위해 NDA 하에 귀하의 이름을 알고자 요청했습니다. 귀하가 승인하고 NDA가 체결되기 전에는 아무것도 공유되지 않습니다. 거절해도 불이익이 없습니다.","tc.accept":"수락","tc.decline":"거절","lp.compRecord":"NDA 하에 공개됨: {name} \xb7 {date} \xb7 참조 {ref}","lp.compDeclined":"작업자가 이 실명 공개를 거절했습니다. 대안은 컨시어지와 상의하세요.","lp.maskDeclined":"탤런트가 이 마일스톤의 라이브 세션을 거절했습니다. 컨시어지가 질문을 대신 전달할 수 있습니다.","op.kindCatalog":"카탈로그 작업 \xb7 4배 하한","op.kindCommission":"커미션 작업 \xb7 1.75배 하한","pp.lic":"라이선스 유형","vu.perpNote":"영구 라이선스는 1회 결제이며 갱신이 없습니다. 반복 수입 대신 더 단순한 판매를 택하는 것입니다. 이 작업으로 계속 수입을 원한다면 기간제 또는 사용별을 선택하세요.","tb.ladderT":"나의 수주 사다리","tb.capCount":"클린 납품(전액 결제, 분쟁 없음): {n}건, {c}명의 클라이언트로부터. $10,000 이상 단계는 서로 다른 클라이언트 2명 이상이 필요합니다.","tb.fastTrack":"다른 곳에서 경력이 있으신가요? 컨시어지에게 레퍼런스 패스트트랙을 문의하세요.","pp.same":"이전에 함께 작업한 바로 그 탤런트(요청에 따라)","vu.portfolio":"먼저 포트폴리오 링크(Dribbble, GitHub, 개인 사이트)를 등록하세요. 공개된 작업물이 심사에서 본인 저작의 증거로 인정되며, 표절 의심의 근거가 되지 않습니다.","faq.q10":"탤런트와 대화할 수 있나요? 작업물을 완전히 살 수 있나요?","faq.a10":"크리에이티브 작업은 마일스톤당 1회 라이브 세션을 요청할 수 있습니다. 플랫폼이 주최하고 음성이 변조되며 탤런트가 동의한 경우에만 진행됩니다. 나만을 위해 의뢰한 작품이라면 완전 매입도 문의하세요. 맞춤 커미션의 양도 하한(라이선스 가격의 1.75배)은 카탈로그 작품(4배)보다 낮습니다."}')}}]);